package config

import (
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"strings"
)

// Config is the top-level server configuration. Immutable after startup.
type Config struct {
	Embedder  EmbedderConfig  `json:"embedder"`
	Knowledge KnowledgeConfig `json:"knowledge"`
	Search    SearchConfig    `json:"search"`
	Security  SecurityConfig  `json:"security"`
	Log       LogConfig       `json:"log"`
	IndexPath string          `json:"indexPath"`
}

// EmbedderConfig controls the embedding backend.
type EmbedderConfig struct {
	Backend    string       `json:"backend"`
	Model      string       `json:"model"`
	Dimensions int          `json:"dimensions"`
	MaxTokens  int          `json:"maxTokens"`
	Ollama     OllamaConfig `json:"ollama"`
}

// OllamaConfig is Ollama-specific configuration.
type OllamaConfig struct {
	Host string `json:"host"`
}

// KnowledgeConfig controls knowledge indexing behaviour.
type KnowledgeConfig struct {
	GlobalSources []string `json:"globalSources"`
	MaxChunkSize  int      `json:"maxChunkSize"`
}

// SearchConfig controls search tuning parameters.
type SearchConfig struct {
	BM25Weight   float64 `json:"bm25Weight"`
	KNNWeight    float64 `json:"knnWeight"`
	RRFK         int     `json:"rrfK"`
	DefaultLimit int     `json:"defaultLimit"`
	MaxLimit     int     `json:"maxLimit"`
}

// SecurityConfig controls security filtering during indexing.
type SecurityConfig struct {
	ExtensionAllowlist []string `json:"extensionAllowlist"`
	FilenameBlocklist  []string `json:"filenameBlocklist"`
	DirectoryBlocklist []string `json:"directoryBlocklist"`
	MaxFileSizeBytes   int64    `json:"maxFileSizeBytes"`
}

// LogConfig controls logging behaviour.
type LogConfig struct {
	Level string `json:"level"`
}

// Defaults returns a Config with all fields populated to their defaults.
func Defaults() Config {
	return Config{
		Embedder: EmbedderConfig{
			Backend:    "ollama",
			Model:      "nomic-embed-text:v1.5",
			Dimensions: 768,
			MaxTokens:  8192,
			Ollama: OllamaConfig{
				Host: "http://localhost:11434",
			},
		},
		Knowledge: KnowledgeConfig{
			MaxChunkSize: 16000,
		},
		Search: SearchConfig{
			BM25Weight:   0.4,
			KNNWeight:    0.6,
			RRFK:         60,
			DefaultLimit: 5,
			MaxLimit:     20,
		},
		Security: SecurityConfig{
			ExtensionAllowlist: []string{".md", ".txt"},
			FilenameBlocklist:  []string{".env.md", ".env.txt", "credentials.md"},
			DirectoryBlocklist: []string{"node_modules", ".git", "__pycache__", "vendor"},
			MaxFileSizeBytes:   1 * 1024 * 1024, // 1 MB
		},
		Log: LogConfig{
			Level: "info",
		},
		IndexPath: "knowledge.bleve",
	}
}

// Load reads configuration from a JSON file path and applies env var overrides.
// If path is empty, returns defaults with env overrides applied.
func Load(path string) (Config, error) {
	cfg := Defaults()

	if path != "" {
		data, err := os.ReadFile(path)
		if err != nil {
			return Config{}, fmt.Errorf("reading config file: %w", err)
		}
		if err := json.Unmarshal(data, &cfg); err != nil {
			return Config{}, fmt.Errorf("parsing config file: %w", err)
		}
		// Re-apply defaults for zero-value fields that weren't in the JSON
		cfg = mergeDefaults(cfg)
	}

	applyEnvOverrides(&cfg)
	return cfg, nil
}

// mergeDefaults fills in zero-value fields with defaults.
func mergeDefaults(cfg Config) Config {
	d := Defaults()

	if cfg.Embedder.Backend == "" {
		cfg.Embedder.Backend = d.Embedder.Backend
	}
	if cfg.Embedder.Model == "" {
		cfg.Embedder.Model = d.Embedder.Model
	}
	if cfg.Embedder.Dimensions == 0 {
		cfg.Embedder.Dimensions = d.Embedder.Dimensions
	}
	if cfg.Embedder.MaxTokens == 0 {
		cfg.Embedder.MaxTokens = d.Embedder.MaxTokens
	}
	if cfg.Embedder.Ollama.Host == "" {
		cfg.Embedder.Ollama.Host = d.Embedder.Ollama.Host
	}
	if cfg.Knowledge.MaxChunkSize == 0 {
		cfg.Knowledge.MaxChunkSize = d.Knowledge.MaxChunkSize
	}
	if cfg.Search.BM25Weight == 0 {
		cfg.Search.BM25Weight = d.Search.BM25Weight
	}
	if cfg.Search.KNNWeight == 0 {
		cfg.Search.KNNWeight = d.Search.KNNWeight
	}
	if cfg.Search.RRFK == 0 {
		cfg.Search.RRFK = d.Search.RRFK
	}
	if cfg.Search.DefaultLimit == 0 {
		cfg.Search.DefaultLimit = d.Search.DefaultLimit
	}
	if cfg.Search.MaxLimit == 0 {
		cfg.Search.MaxLimit = d.Search.MaxLimit
	}
	if len(cfg.Security.ExtensionAllowlist) == 0 {
		cfg.Security.ExtensionAllowlist = d.Security.ExtensionAllowlist
	}
	if len(cfg.Security.FilenameBlocklist) == 0 {
		cfg.Security.FilenameBlocklist = d.Security.FilenameBlocklist
	}
	if len(cfg.Security.DirectoryBlocklist) == 0 {
		cfg.Security.DirectoryBlocklist = d.Security.DirectoryBlocklist
	}
	if cfg.Security.MaxFileSizeBytes == 0 {
		cfg.Security.MaxFileSizeBytes = d.Security.MaxFileSizeBytes
	}
	if cfg.Log.Level == "" {
		cfg.Log.Level = d.Log.Level
	}
	if cfg.IndexPath == "" {
		cfg.IndexPath = d.IndexPath
	}

	return cfg
}

// applyEnvOverrides reads RAG_MCP_* environment variables and overrides config values.
func applyEnvOverrides(cfg *Config) {
	if v := os.Getenv("RAG_MCP_EMBEDDER_BACKEND"); v != "" {
		cfg.Embedder.Backend = v
	}
	if v := os.Getenv("RAG_MCP_EMBEDDER_MODEL"); v != "" {
		cfg.Embedder.Model = v
	}
	if v := os.Getenv("RAG_MCP_EMBEDDER_DIMENSIONS"); v != "" {
		if n, err := strconv.Atoi(v); err == nil && n > 0 {
			cfg.Embedder.Dimensions = n
		}
	}
	if v := os.Getenv("RAG_MCP_OLLAMA_HOST"); v != "" {
		cfg.Embedder.Ollama.Host = v
	}
	if v := os.Getenv("RAG_MCP_INDEX_PATH"); v != "" {
		cfg.IndexPath = v
	}
	if v := os.Getenv("RAG_MCP_LOG_LEVEL"); v != "" {
		cfg.Log.Level = v
	}
	if v := os.Getenv("RAG_MCP_MAX_CHUNK_SIZE"); v != "" {
		if n, err := strconv.Atoi(v); err == nil && n > 0 {
			cfg.Knowledge.MaxChunkSize = n
		}
	}
	if v := os.Getenv("RAG_MCP_GLOBAL_SOURCES"); v != "" {
		cfg.Knowledge.GlobalSources = strings.Split(v, ",")
	}
}
